/**
 * Unit tests for stop/handoff-writer hook
 *
 * Tests writing .claude/HANDOFF.md on session stop with:
 * - Summary extraction from last_assistant_message
 * - Modified files from git diff
 * - Recent decisions from decisions.jsonl
 * - Recent tasks from task-completions.jsonl
 * - Structured learnings via learning-extractor
 * - Error resilience (always returns silent success)
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
    getProjectDir: vi.fn(() => '/test/project'),
    getSessionId: vi.fn(() => 'session-stop-001'),
    getCachedBranch: vi.fn(() => 'feat/test-feature'),
  };
});

// Mock node:fs to avoid touching the real filesystem
const mockExistsSync = vi.fn();
const mockReadFileSync = vi.fn();
const mockMkdirSync = vi.fn();
const mockWriteFileSync = vi.fn();

vi.mock('node:fs', () => ({
  existsSync: (...args: unknown[]) => mockExistsSync(...args),
  readFileSync: (...args: unknown[]) => mockReadFileSync(...args),
  mkdirSync: (...args: unknown[]) => mockMkdirSync(...args),
  writeFileSync: (...args: unknown[]) => mockWriteFileSync(...args),
}));

// Mock node:child_process
const mockExecSync = vi.fn(() => '');

vi.mock('node:child_process', () => ({
  execSync: (cmd: string, options?: unknown) => (mockExecSync as (cmd: string, opts?: unknown) => string)(cmd, options),
}));

// Mock atomic-write so atomicWriteSync delegates to mockWriteFileSync
vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: (path: string, content: string) => mockWriteFileSync(path, content, 'utf8'),
}));

// Mock learning-extractor
vi.mock('../../lib/learning-extractor.js', () => ({
  extractLearnings: vi.fn(() => []),
  formatLearnings: vi.fn(() => ''),
}));

import { handoffWriter } from '../../stop/handoff-writer.js';
import { logHook } from '../../lib/common.js';
import { extractLearnings, formatLearnings } from '../../lib/learning-extractor.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createStopInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'Stop',
    tool_name: '',
    session_id: 'test-session-stop-001',
    tool_input: {},
    project_dir: '/test/project',
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('stop/handoff-writer', () => {
  beforeEach(() => {
    vi.resetAllMocks();
    // Default: .claude/ exists, no decisions/tasks files
    mockExistsSync.mockImplementation((p: string) => {
      if (p === '/test/project/.claude') return true;
      return false;
    });
    mockReadFileSync.mockReturnValue('');
    mockExecSync.mockReturnValue('');
    vi.mocked(extractLearnings).mockReturnValue([]);
    vi.mocked(formatLearnings).mockReturnValue('');
  });

  // -------------------------------------------------------------------------
  // Always returns silent success
  // -------------------------------------------------------------------------

  describe('always returns silent success', () => {
    it('returns { continue: true, suppressOutput: true }', () => {
      const input = createStopInput();
      const result = handoffWriter(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    it('returns silent success even when writeFileSync throws', () => {
      mockWriteFileSync.mockImplementation(() => { throw new Error('disk full'); });

      const input = createStopInput();
      const result = handoffWriter(input);

      expect(result.continue).toBe(true);
    });

    it('returns silent success even when execSync throws', () => {
      mockExecSync.mockImplementation(() => { throw new Error('git not available'); });

      const input = createStopInput();
      const result = handoffWriter(input);

      expect(result.continue).toBe(true);
    });

    it('logs failure warning when write fails (non-blocking)', () => {
      mockWriteFileSync.mockImplementation(() => { throw new Error('write error'); });

      const input = createStopInput();
      handoffWriter(input);

      expect(logHook).toHaveBeenCalledWith(
        'handoff-writer',
        expect.stringContaining('Failed to write handoff'),
        'warn',
      );
    });
  });

  // -------------------------------------------------------------------------
  // Writes HANDOFF.md with expected content
  // -------------------------------------------------------------------------

  describe('HANDOFF.md content', () => {
    it('writes to .claude/HANDOFF.md', () => {
      const input = createStopInput();
      handoffWriter(input);

      expect(mockWriteFileSync).toHaveBeenCalledWith(
        '/test/project/.claude/HANDOFF.md',
        expect.any(String),
        'utf8',
      );
    });

    it('includes # Session Handoff heading', () => {
      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('# Session Handoff');
    });

    it('includes branch name from getCachedBranch', () => {
      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('feat/test-feature');
    });

    it('includes session ID', () => {
      const input = createStopInput({ session_id: 'my-explicit-session' });
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('my-explicit-session');
    });

    it('includes ## Summary section', () => {
      const input = createStopInput({ last_assistant_message: 'I fixed the auth bug by updating the JWT validation.' });
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('## Summary');
    });

    it('includes fallback summary when last_assistant_message is absent', () => {
      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('No summary available.');
    });

    it('includes timestamp in UTC format', () => {
      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('UTC');
    });
  });

  // -------------------------------------------------------------------------
  // Modified files section
  // -------------------------------------------------------------------------

  describe('modified files section', () => {
    it('includes ## Modified Files when git diff returns files', () => {
      mockExecSync.mockReturnValue('src/hooks/src/stop/handoff-writer.ts\npackage.json\n');

      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('## Modified Files');
      expect(content).toContain('handoff-writer.ts');
      expect(content).toContain('package.json');
    });

    it('omits ## Modified Files section when git diff returns nothing', () => {
      mockExecSync.mockReturnValue('');

      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).not.toContain('## Modified Files');
    });

    it('handles git not available gracefully', () => {
      mockExecSync.mockImplementation(() => { throw new Error('git: command not found'); });

      const input = createStopInput();
      expect(() => handoffWriter(input)).not.toThrow();
    });
  });

  // -------------------------------------------------------------------------
  // Decisions section (fallback when no learnings)
  // -------------------------------------------------------------------------

  describe('decisions fallback', () => {
    it('includes ## Decisions Made when decisions.jsonl exists and learnings is empty', () => {
      const decisionsEntry = JSON.stringify({ summary: 'Chose PostgreSQL over MongoDB' });
      mockExistsSync.mockImplementation((p: string) => {
        if (p === '/test/project/.claude') return true;
        if (p === '/test/project/.claude/logs/decisions.jsonl') return true;
        return false;
      });
      mockReadFileSync.mockReturnValue(`${decisionsEntry}\n`);
      vi.mocked(formatLearnings).mockReturnValue(''); // no learnings

      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('## Decisions Made');
      expect(content).toContain('Chose PostgreSQL over MongoDB');
    });

    it('omits decisions section when decisions.jsonl does not exist', () => {
      mockExistsSync.mockReturnValue(false);

      const input = createStopInput();
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).not.toContain('## Decisions Made');
    });
  });

  // -------------------------------------------------------------------------
  // Learning extractor integration
  // -------------------------------------------------------------------------

  describe('learning extractor integration', () => {
    it('calls extractLearnings with last_assistant_message', () => {
      const msg = 'I decided to use Vitest. Fixed by removing stale cache.';
      const input = createStopInput({ last_assistant_message: msg });
      handoffWriter(input);

      expect(extractLearnings).toHaveBeenCalledWith(msg);
    });

    it('includes formatLearnings output when learnings exist', () => {
      vi.mocked(extractLearnings).mockReturnValue([{ type: 'Decision', content: 'Used Vitest.' }]);
      vi.mocked(formatLearnings).mockReturnValue('## Decisions Made\n- Used Vitest.');

      const input = createStopInput({ last_assistant_message: 'I decided to use Vitest.' });
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('## Decisions Made');
      expect(content).toContain('Used Vitest.');
    });
  });

  // -------------------------------------------------------------------------
  // .claude/ directory creation
  // -------------------------------------------------------------------------

  describe('.claude/ directory', () => {
    it('creates .claude/ directory if it does not exist', () => {
      mockExistsSync.mockReturnValue(false);

      const input = createStopInput();
      handoffWriter(input);

      expect(mockMkdirSync).toHaveBeenCalledWith(
        '/test/project/.claude',
        { recursive: true },
      );
    });

    it('does not call mkdirSync when .claude/ already exists', () => {
      mockExistsSync.mockReturnValue(true);

      const input = createStopInput();
      handoffWriter(input);

      expect(mockMkdirSync).not.toHaveBeenCalled();
    });
  });

  // -------------------------------------------------------------------------
  // Summary truncation
  // -------------------------------------------------------------------------

  describe('summary truncation', () => {
    it('truncates very long last_assistant_message', () => {
      const longMessage = 'A '.repeat(1000); // 2000 chars
      const input = createStopInput({ last_assistant_message: longMessage });
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      // The content written should not contain the full 2000-char message verbatim
      expect(content.length).toBeLessThan(longMessage.length + 500); // reasonable bound
    });

    it('appends ellipsis when message is truncated', () => {
      const longMessage = 'word '.repeat(300); // >600 chars, no sentence boundary
      const input = createStopInput({ last_assistant_message: longMessage });
      handoffWriter(input);

      const content: string = mockWriteFileSync.mock.calls[0][1];
      expect(content).toContain('...');
    });
  });

  // -------------------------------------------------------------------------
  // Logging
  // -------------------------------------------------------------------------

  describe('logging', () => {
    it('logs success with file path and stats after successful write', () => {
      // Ensure writeFileSync is not throwing for this test
      mockWriteFileSync.mockReturnValue(undefined);

      const input = createStopInput();
      handoffWriter(input);

      // logHook should have been called with handoff-writer and a message containing HANDOFF.md
      const calls = vi.mocked(logHook).mock.calls;
      const hasSuccessLog = calls.some(
        ([name, msg]) => name === 'handoff-writer' && String(msg).includes('HANDOFF.md'),
      );
      expect(hasSuccessLog).toBe(true);
    });
  });
});
